	if !ok {
		return nil, fmt.Errorf("invalid groupByField: %s", groupByField)
	}

	placeholders := make([]string, 0, len(departments))
	args := make([]interface{}, 0, len(departments))
	for _, dept := range departments {
		placeholders = append(placeholders, "?")
		args = append(args, dept)
	}

	sql := `
SELECT
	u.` + col + ` as group_value,
	COUNT(DISTINCT u.id) as user_count,
	COUNT(a.id) as total_activities
FROM user_profile u
LEFT JOIN user_activity a ON u.id = a.user_id
WHERE u.department IN (` + strings.Join(placeholders, ",") + `)
GROUP BY u.` + col + `
ORDER BY u.` + col

	// beego orm.Raw().Values expects *[]orm.Params
	var params []orm.Params
	_, err := o.Raw(sql, args...).Values(&params)
	if err != nil {
		return nil, err
	}

