//
// Returns a slice of maps with keys: "group_value" (the grouped field value), "user_count", "total_activities"
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	if o == nil {
		return nil, errors.New("orm: nil Ormer")
	}
	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	var groupCol string
	switch groupByField {
	case "department":
		groupCol = "u.department"
	case "role":
		groupCol = "u.role"
	case "display_name":
		groupCol = "u.display_name"
	default:
		return nil, fmt.Errorf("invalid groupByField: %s", groupByField)
	}

	inDepts, deptArgs := makeInClauseArgs(departments)

	// Count distinct users and total activities (including users with 0 activities).
	sql := fmt.Sprintf(`
SELECT
  %s AS group_value,
  COUNT(DISTINCT u.id) AS user_count,
  COUNT(a.id) AS total_activities
FROM user_profile u
LEFT JOIN user_activity a ON a.user_id = u.id
WHERE u.department IN (%s)
GROUP BY %s
ORDER BY %s`, groupCol, inDepts, groupCol, groupCol)

	var rows []orm.Params
	if _, err := o.Raw(sql, deptArgs...).Values(&rows); err != nil {
		return nil, err
	}

	out := make([]map[string]interface{}, 0, len(rows))
	for _, r := range rows {
		m := map[string]interface{}{
			"group_value":      r["group_value"],
			"user_count":       r["user_count"],
			"total_activities": r["total_activities"],
		}
		out = append(out, m)
	}
	return out, nil
}

func makeInClauseArgs(ss []string) (placeholders string, args []any) {
	if len(ss) == 0 {
		return "", nil
	}
	var b strings.Builder
	args = make([]any, 0, len(ss))
	for i, s := range ss {
		if i > 0 {
			b.WriteString(",")
		}
		b.WriteString("?")
		args = append(args, s)
	}
	return b.String(), args
}

