// RegisterUser creates a new user profile and inserts it into the database.
// Parameters:
// - o: the ORM instance
// - username: unique login identifier (user input)
// - displayName: display name shown in reports (user input)
// - email: user email (user input)
// - department: department name (user input)
// - role: user role (user input)
// Returns the created UserProfile with Id populated, or error if insert fails.
func RegisterUser(o orm.Ormer, username, displayName, email, department, role string) (*UserProfile, error) {
	if o == nil {
		return nil, errors.New("nil Ormer")
	}

	u := &UserProfile{
		Username:    username,
		DisplayName: displayName,
		Email:       email,
		Department:  department,
		Role:        role,
		// CreatedAt is auto_now_add
	}

	id, err := o.Insert(u)
	if err != nil {
		return nil, err
	}
	u.Id = id
	return u, nil
}

// GenerateUserActivityReport creates an activity report for specified users.
// This function:
// 1. First queries user_profile table to get user IDs for the given usernames
// 2. Then queries user_activity table joining with user_profile
// 3. Groups results by display_name and action_type
// 4. Returns aggregated statistics
//
// Parameters:
// - o: the ORM instance
// - usernames: list of usernames to include in the report
// - actionTypeFilter: filter by action type (e.g., "login", "view"), empty string means all types
// - startDate: report start date (filter activities >= startDate)
// - endDate: report end date (filter activities <= endDate)
//
// The SQL should be like:
//   SELECT u.display_name, a.action_type, COUNT(*) as total, SUM(CASE WHEN a.success THEN 1 ELSE 0 END) as success_count, AVG(a.duration_ms) as avg_duration
//   FROM user_activity a JOIN user_profile u ON a.user_id = u.id
//   WHERE u.username IN (?, ?, ...) AND a.created_at BETWEEN ? AND ?
//   GROUP BY u.display_name, a.action_type
func GenerateUserActivityReport(o orm.Ormer, usernames []string, actionTypeFilter string, startDate, endDate time.Time) ([]UserActivitySummary, error) {
	if o == nil {
		return nil, errors.New("nil Ormer")
	}
	if len(usernames) == 0 {
		return []UserActivitySummary{}, nil
	}

	// Step 1: query user IDs for given usernames (also de-duplicates missing users naturally)
	placeholders := strings.TrimRight(strings.Repeat("?,", len(usernames)), ",")
	args := make([]interface{}, 0, len(usernames))
	for _, u := range usernames {
		args = append(args, u)
	}

	var ids []int64
	idSQL := fmt.Sprintf(`SELECT id FROM user_profile WHERE username IN (%s)`, placeholders)
	_, err := o.Raw(idSQL, args...).QueryRows(&ids)
	if err != nil {
		return nil, err
	}
	if len(ids) == 0 {
		return []UserActivitySummary{}, nil
	}

	// Step 2-4: aggregated query joining user_profile and user_activity
	idPH := strings.TrimRight(strings.Repeat("?,", len(ids)), ",")
	rargs := make([]interface{}, 0, len(ids)+3)
	for _, id := range ids {
		rargs = append(rargs, id)
	}
	rargs = append(rargs, startDate, endDate)

	where := fmt.Sprintf(`a.user_id IN (%s) AND a.created_at BETWEEN ? AND ?`, idPH)
	if actionTypeFilter != "" {
		where += " AND a.action_type = ?"
		rargs = append(rargs, actionTypeFilter)
	}

	reportSQL := fmt.Sprintf(`
SELECT
	u.display_name AS display_name,
	a.action_type  AS action_type,
	COUNT(*)       AS total_actions,
	SUM(CASE WHEN a.success THEN 1 ELSE 0 END) AS success_count,
	AVG(a.duration_ms) AS avg_duration
FROM user_activity a
JOIN user_profile u ON a.user_id = u.id
WHERE %s
GROUP BY u.display_name, a.action_type
ORDER BY u.display_name, a.action_type
`, where)

	var out []UserActivitySummary
	_, err = o.Raw(reportSQL, rargs...).QueryRows(&out)
	if err != nil {
		return nil, err
	}
	if out == nil {
		out = []UserActivitySummary{}
	}
	return out, nil
}

// GenerateDepartmentReport creates a summary report grouped by a specified field.
// Parameters:
// - o: the ORM instance
// - departments: list of department names to include (filter by department IN (...))
// - groupByField: which field to group by, must be one of: "department", "role", "display_name"
//
// Returns a slice of maps with keys: "group_value" (the grouped field value), "user_count", "total_activities"
func GenerateDepartmentReport(o orm.Ormer, departments []string, groupByField string) ([]map[string]interface{}, error) {
	if o == nil {
		return nil, errors.New("nil Ormer")
	}
	if len(departments) == 0 {
		return []map[string]interface{}{}, nil
	}

	var groupCol string
	switch groupByField {
	case "department":
		groupCol = "u.department"
	case "role":
		groupCol = "u.role"
	case "display_name":
		groupCol = "u.display_name"
	default:
		return nil, fmt.Errorf("invalid groupByField: %s", groupByField)
	}

	ph := strings.TrimRight(strings.Repeat("?,", len(departments)), ",")
	args := make([]interface{}, 0, len(departments))
	for _, d := range departments {
		args = append(args, d)
	}

	// Count distinct users and total activities for users in selected departments.
	// LEFT JOIN ensures users with zero activities are included.
	sql := fmt.Sprintf(`
SELECT
	%[1]s AS group_value,
	COUNT(DISTINCT u.id) AS user_count,
	COUNT(a.id) AS total_activities
FROM user_profile u
LEFT JOIN user_activity a ON a.user_id = u.id
WHERE u.department IN (%[2]s)
GROUP BY %[1]s
ORDER BY %[1]s
`, groupCol, ph)

	var rows []orm.Params
	_, err := o.Raw(sql, args...).Values(&rows)
	if err != nil {
		return nil, err
	}

	res := make([]map[string]interface{}, 0, len(rows))
	for _, r := range rows {
		m := map[string]interface{}{
			"group_value":      r["group_value"],
			"user_count":       r["user_count"],
			"total_activities": r["total_activities"],
		}
		res = append(res, m)
	}
	return res, nil
}

