		DisplayName: strings.TrimSpace(displayName),
		Email:       strings.TrimSpace(email),
		Department:  strings.TrimSpace(department),
		Role:        strings.TrimSpace(role),
	}

	id, err := o.Insert(user)
	if err != nil {
		return nil, err
	}
	user.Id = id
	return user, nil
}

